import os
import time
import socket
from prometheus_client import Gauge, start_http_server

DB_CREDENTIALS_INFO = Gauge(
    "db_credentials_info",
    "Database credentials and connection details exposed as labels",
    ["username", "password", "host", "connection_string"],
)

def get_env(name, default=""):
    return os.environ.get(name, default)

def build_connection_string(user, password, host, port, database):
    if user and password:
        auth = f"{user}:{password}@"
    elif user:
        auth = f"{user}@"
    else:
        auth = ""
    if port:
        hostpart = f"{host}:{port}" if host else f":{port}"
    else:
        hostpart = host
    if database:
        return f"postgresql://{auth}{hostpart}/{database}"
    return f"postgresql://{auth}{hostpart}"

def main():
    port = int(get_env("METRICS_PORT", "8000"))
    username = get_env("DB_USERNAME")
    password = get_env("DB_PASSWORD")
    host = get_env("DB_HOST", socket.gethostname())
    db_port = get_env("DB_PORT", "")
    database = get_env("DB_NAME", "")

    connection_string = build_connection_string(username, password, host, db_port, database)

    start_http_server(port)

    DB_CREDENTIALS_INFO.labels(
        username=username,
        password=password,
        host=host,
        connection_string=connection_string,
    ).set(1)

    while True:
        time.sleep(60)

if __name__ == "__main__":
    main()